mapper.select:
SELECT * FROM ( SELECT * FROM ( SELECT th.history_id, th.task_id, t.project_id AS projectId, p.project_title AS projectTitle, u.user_name AS userName, u.profile_image AS profileImage, NVL(d_title.new_value, t.task_title) AS taskTitle, NVL(d_type.new_value, tt.type_name) AS typeName, cc.default_describe AS defaultDescribe, th.action_type AS actionType, th.action_at AS actionAt FROM task_history th INNER JOIN task t ON th.task_id = t.task_id INNER JOIN users u ON th.changed_by = u.user_code INNER JOIN task_types tt ON t.type_id = tt.type_id LEFT JOIN project p ON t.project_id = p.project_id LEFT JOIN task_history_detail d_title ON th.history_id = d_title.history_id AND d_title.field_name = 'task_title' LEFT JOIN task_history_detail d_type ON th.history_id = d_type.history_id AND d_type.field_name = 'type_name' LEFT OUTER JOIN common_code cc ON t.task_status = cc.common_id AND cc.common_code = '0E'
AND th.action_at >= TRUNC(SYSDATE) - 3
AND t.project_id IN
#{pId}
UNION ALL
SELECT NULL AS history_id, w.wiki_page_id AS task_id, w.project_id AS projectId, p2.project_title AS projectTitle, u2.user_name AS userName, u2.profile_image AS profileImage, w.title AS taskTitle, '위키' AS typeName, '위키 생성' AS defaultDescribe, 'CREATE' AS actionType, w.created_at AS actionAt FROM wiki_pages w JOIN users u2 ON w.user_code = u2.user_code LEFT JOIN project p2 ON w.project_id = p2.project_id
AND w.created_at >= TRUNC(SYSDATE) - 3
AND w.project_id IN
#{pId}
UNION ALL
SELECT NULL AS history_id, wp.wiki_page_id AS task_id, wp.project_id AS projectId, p3.project_title AS projectTitle, u3.user_name AS userName, u3.profile_image AS profileImage, h.title AS taskTitle, '위키' AS typeName, '위키 수정' AS defaultDescribe, 'UPDATE' AS actionType, h.created_at AS actionAt FROM wiki_histories h JOIN wiki_pages wp ON h.wiki_page_id = wp.wiki_page_id JOIN users u3 ON h.user_code = u3.user_code LEFT JOIN project p3 ON wp.project_id = p3.project_id
AND h.created_at >= TRUNC(SYSDATE) - 3
AND wp.project_id IN
#{pId}
) ORDER BY actionAt DESC ) WHERE ROWNUM <= #{limit}
